                undoIcon.title = resources.getString(R.string.undo)
            }

            if (getColUnsafe.redoAvailable()) {
                redoIcon.title = getColUnsafe.redoLabel()
            } else {
                redoIcon.title = resources.getString(R.string.redo)
            }
        }
