 42→/**
 43→ * Runs a suspend function that catches any uncaught errors and reports them to the user.
 44→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
 45→ * Other errors should ideally be handled in the block.
 46→ *
 47→ * TODO: `Throwable.getLocalizedMessage()` might be null, and `BackendException` constructor
 48→ *   accepts a null message, so `exc.localizedMessage!!` is probably dangerous.
 49→ *   If not, add a comment explaining why, or refactor to have a method that returns
 50→ *   a non-null localized message.
 51→ */
 52→suspend fun <T> FragmentActivity.runCatchingTask(
 53→    errorMessage: String? = null,
 54→    block: suspend () -> T?
 55→): T? {
 56→    try {
 57→        return block()
 58→    } catch (cancellationException: CancellationException) {
 59→        throw cancellationException // CancellationException should be re-thrown to propagate it to the parent coroutine
 60→    } catch (exc: BackendInterruptedException) {
 61→        Timber.e(exc, errorMessage)
 62→        exc.localizedMessage?.let { showSnackbar(it) }
 63→    } catch (exc: BackendException) {
 64→        Timber.e(exc, errorMessage)
 65→        showError(this, exc.localizedMessage!!, exc)
 66→    } catch (exc: Exception) {
 67→        Timber.e(exc, errorMessage)
 68→        showError(this, exc.toString(), exc)
 69→    }
 70→    return null
 71→}
 72→
 73→/**
 74→ * Returns CoroutineExceptionHandler which catches any uncaught exceptions and reports it to user
 75→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
 76→ * Other errors should ideally be handled in the block.
 77→ *
 78→ * Typically you'll want to use [launchCatchingTask] instead; this routine is mainly useful for
 79→ * launching tasks in an activity that is not a lifecycleOwner.
 80→ *
 81→ * @return [CoroutineExceptionHandler]
 82→ * @see [FragmentActivity.launchCatchingTask]
 83→ */
 84→fun getCoroutineExceptionHandler(activity: Activity, errorMessage: String? = null) =
 85→    CoroutineExceptionHandler { _, throwable ->
 86→        // No need to check for cancellation-exception, it does not gets caught by CoroutineExceptionHandler
 87→        when (throwable) {
 88→            is BackendInterruptedException -> {
 89→                Timber.e(throwable, errorMessage)
 90→                throwable.localizedMessage?.let { activity.showSnackbar(it) }
 91→            }
 92→            is BackendException -> {
 93→                Timber.e(throwable, errorMessage)
 94→                showError(activity, throwable.localizedMessage!!, throwable)
 95→            }
 96→            else -> {
 97→                Timber.e(throwable, errorMessage)
 98→                showError(activity, throwable.toString(), throwable)
 99→            }
100→        }
101→    }
102→
103→/**
104→ * Launch a job that catches any uncaught errors and reports them to the user.
105→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
106→ * Other errors should ideally be handled in the block.
107→ */
108→fun FragmentActivity.launchCatchingTask(
109→    errorMessage: String? = null,
110→    block: suspend CoroutineScope.() -> Unit
111→): Job {
112→    return lifecycle.coroutineScope.launch {
113→        runCatchingTask(errorMessage) { block() }
114→    }
115→}
116→
117→/** See [FragmentActivity.launchCatchingTask] */
118→fun Fragment.launchCatchingTask(
119→    errorMessage: String? = null,
120→    block: suspend CoroutineScope.() -> Unit
121→): Job {
122→    return lifecycle.coroutineScope.launch {
123→        requireActivity().runCatchingTask(errorMessage) { block() }
124→    }
125→}
