146→/** In most cases, you'll want [AnkiActivity.withProgress]
147→ * instead. This lower-level routine can be used to integrate your own
148→ * progress UI.
149→ */
150→suspend fun <T> Backend.withProgress(
151→    extractProgress: ProgressContext.() -> Unit,
152→    updateUi: ProgressContext.() -> Unit,
153→    block: suspend CoroutineScope.() -> T
154→): T {
155→    return coroutineScope {
156→        val monitor = launch {
157→            monitorProgress(this@withProgress, extractProgress, updateUi)
158→        }
159→        try {
160→            block()
161→        } finally {
162→            monitor.cancel()
163→        }
164→    }
165→}
