167→/**
168→ * Run the provided operation, showing a progress window until it completes.
169→ * Progress info is polled from the backend.
170→ *
171→ * Starts the progress dialog after 600ms so that quick operations don't just show
172→ * flashes of a dialog.
173→ */
174→suspend fun <T> FragmentActivity.withProgress(
175→    extractProgress: ProgressContext.() -> Unit,
176→    onCancel: ((Backend) -> Unit)? = { it.setWantsAbort() },
177→    op: suspend () -> T
178→): T {
179→    val backend = CollectionManager.getBackend()
180→    return withProgressDialog(
181→        context = this@withProgress,
182→        onCancel = if (onCancel != null) {
183→            fun() { onCancel(backend) }
184→        } else {
185→            null
186→        }
187→    ) { dialog ->
188→        backend.withProgress(
189→            extractProgress = extractProgress,
190→            updateUi = { updateDialog(dialog) }
191→        ) {
192→            op()
193→        }
194→    }
195→}
