228→@Suppress("Deprecation") // ProgressDialog deprecation
229→suspend fun <T> withProgressDialog(
230→    context: Activity,
231→    onCancel: (() -> Unit)?,
232→    delayMillis: Long = 600,
233→    op: suspend (android.app.ProgressDialog) -> T
234→): T = coroutineScope {
235→    val dialog = android.app.ProgressDialog(context).apply {
236→        setCancelable(onCancel != null)
237→        onCancel?.let {
238→            setOnCancelListener { it() }
239→        }
240→    }
241→    // disable taps immediately
242→    context.window.setFlags(WindowManager.LayoutParams.FLAG_NOT_TOUCHABLE, WindowManager.LayoutParams.FLAG_NOT_TOUCHABLE)
243→    // reveal the dialog after 600ms
244→    var dialogIsOurs = false
245→    val dialogJob = launch {
246→        delay(delayMillis)
247→        if (!AnkiDroidApp.instance.progressDialogShown) {
248→            dialog.show()
249→            AnkiDroidApp.instance.progressDialogShown = true
250→            dialogIsOurs = true
251→        }
252→    }
253→    try {
254→        op(dialog)
255→    } finally {
256→        dialogJob.cancel()
257→        dialog.dismiss()
258→        context.window.clearFlags(WindowManager.LayoutParams.FLAG_NOT_TOUCHABLE)
259→        if (dialogIsOurs) {
260→            AnkiDroidApp.instance.progressDialogShown = false
261→        }
262→    }
263→}
