265→/**
266→ * Poll the backend for progress info every 100ms until cancelled by caller.
267→ * Calls extractProgress() to gather progress info and write it into
268→ * [ProgressContext]. Calls updateUi() to update the UI with the extracted
269→ * progress.
270→ */
271→private suspend fun monitorProgress(
272→    backend: Backend,
273→    extractProgress: ProgressContext.() -> Unit,
274→    updateUi: ProgressContext.() -> Unit
275→) {
276→    val state = ProgressContext(Progress.getDefaultInstance())
277→    while (true) {
278→        state.progress = backend.latestProgress()
279→        state.extractProgress()
280→        // on main thread, so op can update UI
281→        withContext(Dispatchers.Main) {
282→            state.updateUi()
283→        }
284→        delay(100)
285→    }
286→}
