 42→/**
 43→ * Runs a suspend function that catches any uncaught errors and reports them to the user.
 44→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
 45→ * Other errors should ideally be handled in the block.
 46→ *
 47→ * TODO: `Throwable.getLocalizedMessage()` might be null, and `BackendException` constructor
 48→ *   accepts a null message, so `exc.localizedMessage!!` is probably dangerous.
 49→ *   If not, add a comment explaining why, or refactor to have a method that returns
 50→ *   a non-null localized message.
 51→ */
 52→suspend fun <T> FragmentActivity.runCatchingTask(
 53→    errorMessage: String? = null,
 54→    block: suspend () -> T?
 55→): T? {
 56→    try {
 57→        return block()
 58→    } catch (cancellationException: CancellationException) {
 59→        throw cancellationException // CancellationException should be re-thrown to propagate it to the parent coroutine
 60→    } catch (exc: BackendInterruptedException) {
 61→        Timber.e(exc, errorMessage)
 62→        exc.localizedMessage?.let { showSnackbar(it) }
 63→    } catch (exc: BackendException) {
 64→        Timber.e(exc, errorMessage)
 65→        showError(this, exc.localizedMessage!!, exc)
 66→    } catch (exc: Exception) {
 67→        Timber.e(exc, errorMessage)
 68→        showError(this, exc.toString(), exc)
 69→    }
 70→    return null
 71→}
