 73→/**
 74→ * Returns CoroutineExceptionHandler which catches any uncaught exceptions and reports it to user
 75→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
 76→ * Other errors should ideally be handled in the block.
 77→ *
 78→ * Typically you'll want to use [launchCatchingTask] instead; this routine is mainly useful for
 79→ * launching tasks in an activity that is not a lifecycleOwner.
 80→ *
 81→ * @return [CoroutineExceptionHandler]
 82→ * @see [FragmentActivity.launchCatchingTask]
 83→ */
 84→fun getCoroutineExceptionHandler(activity: Activity, errorMessage: String? = null) =
 85→    CoroutineExceptionHandler { _, throwable ->
 86→        // No need to check for cancellation-exception, it does not gets caught by CoroutineExceptionHandler
 87→        when (throwable) {
 88→            is BackendInterruptedException -> {
 89→                Timber.e(throwable, errorMessage)
 90→                throwable.localizedMessage?.let { activity.showSnackbar(it) }
 91→            }
 92→            is BackendException -> {
 93→                Timber.e(throwable, errorMessage)
 94→                showError(activity, throwable.localizedMessage!!, throwable)
 95→            }
 96→            else -> {
 97→                Timber.e(throwable, errorMessage)
 98→                showError(activity, throwable.toString(), throwable)
 99→            }
100→        }
101→    }
