103→/**
104→ * Launch a job that catches any uncaught errors and reports them to the user.
105→ * Errors from the backend contain localized text that is often suitable to show to the user as-is.
106→ * Other errors should ideally be handled in the block.
107→ */
108→fun FragmentActivity.launchCatchingTask(
109→    errorMessage: String? = null,
110→    block: suspend CoroutineScope.() -> Unit
111→): Job {
112→    return lifecycle.coroutineScope.launch {
113→        runCatchingTask(errorMessage) { block() }
114→    }
115→}
