288→/** Holds the current backend progress, and text/amount properties
289→ * that can be written to in order to update the UI.
290→ */
291→data class ProgressContext(
292→    var progress: Progress,
293→    var text: String = "",
294→    /** If set, shows progress bar with a of b complete. */
295→    var amount: Pair<Int, Int>? = null
296→)
297→
298→@Suppress("Deprecation") // ProgressDialog deprecation
299→private fun ProgressContext.updateDialog(dialog: android.app.ProgressDialog) {
300→    // ideally this would show a progress bar, but MaterialDialog does not support
301→    // setting progress after starting with indeterminate progress, so we just use
302→    // this for now
303→    // this code has since been updated to ProgressDialog, and the above not rechecked
304→    val progressText = amount?.let {
305→        " ${it.first}/${it.second}"
306→    } ?: ""
307→    @Suppress("Deprecation") // ProgressDialog deprecation
308→    dialog.setMessage(text + progressText)
309→}
